#include <stdio.h>

int main() {
    int number = 42;
    int* ptr = &number;

    printf("number degeri: %d\n", number);
    printf("number adresi: %p\n", (void*)&number);
    printf("ptr'nin tuttugu adres: %p\n", (void*)ptr);
    printf("ptr'nin dereference degeri: %d\n", *ptr);

    // Pointer ile degisiklik
    *ptr = 100;
    printf("\nptr araciligiyla degistirildi, number: %d\n", number);

    // Dizi ve pointer iliskisi
    int arr[] = {10, 20, 30, 40, 50};
    int* arrPtr = arr;

    printf("\nDizi elemanlari (pointer ile):\n");
    for (int i = 0; i < 5; i++) {
        printf("arr[%d] = %d (adres: %p)\n", i, *(arrPtr + i), (void*)(arrPtr + i));
    }

    // Pointer aritmetigi
    printf("\nIlk eleman: %d\n", *arrPtr);
    arrPtr++;
    printf("Bir sonraki eleman: %d\n", *arrPtr);

    return 0;
}
